'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes, ReactNode } from 'react'
import { Section } from '../../section/section'
import styles from './cta.module.css'

type HeadingLevel = 1 | 2 | 3

export interface CtaProps extends Omit<HTMLAttributes<HTMLElement>, 'title'> {
  title: ReactNode
  description?: ReactNode
  /** Buttons/links rendered in a row below the description. */
  actions?: ReactNode
  headingLevel?: HeadingLevel
  className?: string | undefined
}

export function Cta({
  title,
  description,
  actions,
  headingLevel = 2,
  className,
  ...props
}: CtaProps) {
  const Heading = `h${headingLevel}` as const
  return (
    <Section className={cn(styles['cta'], className)} {...props}>
      <Heading className={styles['title']}>{title}</Heading>
      {description && <p className={styles['description']}>{description}</p>}
      {actions && <div className={styles['actions']}>{actions}</div>}
    </Section>
  )
}

@layer cascivo.component {
  .cta {
    border-block: 1px solid var(--cascivo-color-border);
    background-color: var(--cascivo-surface-subtle);
  }

  .title {
    font-size: var(--cascivo-text-2xl);
    font-weight: var(--cascivo-font-bold);
    text-wrap: balance;
    text-align: center;
    margin: 0;
  }

  .description {
    font-size: var(--cascivo-text-base);
    color: var(--cascivo-text-secondary);
    text-align: center;
    max-inline-size: 56ch;
    margin-inline: auto;
    margin-block: 0;
  }

  .actions {
    display: flex;
    flex-wrap: wrap;
    gap: var(--cascivo-space-3);
    justify-content: center;
  }
}
